while True:    print("\n=== MENU DA CALCULADORA ===")    print("1. Somar")    print("2. Subtrair")    print("3. Multiplicar")    print("4. Dividir")    print("5. Sair")        opcao = input("Escolha uma opção (1-5): ")        if opcao == "5":        print("Saindo da calculadora. Até mais!")        break            if opcao in ["1", "2", "3", "4"]:        num1 = float(input("Digite o primeiro número: "))        num2 = float(input("Digite o segundo número: "))                if opcao == "1":            print(f"Resultado da Soma: {num1 + num2}")        elif opcao == "2":            print(f"Resultado da Subtração: {num1 - num2}")        elif opcao == "3":            print(f"Resultado da Multiplicação: {num1 * num2}")        elif opcao == "4":            if num2 != 0:                print(f"Resultado da Divisão: {num1 / num2}")            else:                print("Erro: Não dá para dividir por zero!")    else:        print("Opção inválida! Tente novamente.")